"""Data models for Sony VENICE frameline XML files.

Mirrors the XML structure generated by Sony's Frame Line Tool:

.. code-block:: xml

    <FrameLineSetting>
      <FileFormatVersion version="1"/>
      <Group>
        <Item id="0x01001000" label="FileTransfer.CheckingCameraSettings">
          <CameraModel>MPC-3626</CameraModel>
          <ImagerMode>6K 2.39:1</ImagerMode>
        </Item>
      </Group>
      <Group>
        <Item id="0x01002000" label="FileTransfer.FrameLineSettings.TopLeft">
          <Top>0</Top><Left>0.112433</Left>
        </Item>
        <Item id="0x01003000" label="FileTransfer.FrameLineSettings.TopRight">
          <Top>0</Top><Left>0.887566</Left>
        </Item>
        <Item id="0x01004000" label="FileTransfer.FrameLineSettings.BottomLeft">
          <Top>1</Top><Left>0.112433</Left>
        </Item>
        <Item id="0x01005000" label="FileTransfer.FrameLineSettings.BottomRight">
          <Top>1</Top><Left>0.887566</Left>
        </Item>
      </Group>
      <Item id="0x01006000" label="FileTransfer.FrameLineSettings.Type">
        <color>Yellow</color>
      </Item>
    </FrameLineSetting>

Each XML file contains exactly **one** frame line rectangle defined by
4 corner points with normalised coordinates:

- Top: 0.0 = top edge, 1.0 = bottom edge
- Left: 0.0 = left edge, 1.0 = right edge

The camera has two frame line slots (L1 and L2). Each slot is loaded
from a separate XML file. All files use the same ``0x0100xxxx`` item IDs.
"""

from __future__ import annotations

import xml.etree.ElementTree as ET
from dataclasses import dataclass, field
from pathlib import Path

VALID_COLORS = frozenset({"White", "Yellow", "Cyan", "Green", "Magenta", "Red", "Blue"})

_ID_PREFIX = "0x0100"

_CAMERA_SETTINGS_SUFFIX = "1000"
_CORNER_SUFFIXES = {
    "TopLeft": "2000",
    "TopRight": "3000",
    "BottomLeft": "4000",
    "BottomRight": "5000",
}
_TYPE_SUFFIX = "6000"


@dataclass
class CornerPoint:
    """A single corner point in normalised coordinates."""

    top: float = 0.0
    left: float = 0.0


@dataclass
class FrameLineRect:
    """A frame line rectangle defined by its four corners.

    Coordinates are normalised to the active sensor area:
    - Top: 0.0 = top edge, 1.0 = bottom edge
    - Left: 0.0 = left edge, 1.0 = right edge
    """

    top_left: CornerPoint = field(default_factory=CornerPoint)
    top_right: CornerPoint = field(default_factory=CornerPoint)
    bottom_left: CornerPoint = field(default_factory=CornerPoint)
    bottom_right: CornerPoint = field(default_factory=CornerPoint)
    color: str = "White"

    @property
    def left_inset(self) -> float:
        """Fractional distance from the left edge."""
        return self.top_left.left

    @property
    def right_inset(self) -> float:
        """Fractional distance from the right edge."""
        return 1.0 - self.top_right.left

    @property
    def top_inset(self) -> float:
        """Fractional distance from the top edge."""
        return self.top_left.top

    @property
    def bottom_inset(self) -> float:
        """Fractional distance from the bottom edge."""
        return 1.0 - self.bottom_left.top

    @property
    def width_fraction(self) -> float:
        """Fraction of horizontal resolution covered by the rect."""
        return max(0.0, self.top_right.left - self.top_left.left)

    @property
    def height_fraction(self) -> float:
        """Fraction of vertical resolution covered by the rect."""
        return max(0.0, self.bottom_left.top - self.top_left.top)


def frameline_rect_from_insets(
    left: float,
    right: float,
    top: float,
    bottom: float,
    color: str = "White",
) -> FrameLineRect:
    """Build a FrameLineRect from normalised edge insets."""
    return FrameLineRect(
        top_left=CornerPoint(top=top, left=left),
        top_right=CornerPoint(top=top, left=1.0 - right),
        bottom_left=CornerPoint(top=1.0 - bottom, left=left),
        bottom_right=CornerPoint(top=1.0 - bottom, left=1.0 - right),
        color=color,
    )


@dataclass
class CameraSettings:
    """Camera identification embedded in the XML."""

    model_code: str = ""
    imager_mode: str = ""


@dataclass
class SonyFrameline:
    """Root model for a Sony VENICE frameline XML file.

    Each file contains exactly one frame line rectangle. The camera
    has two slots (L1 / L2) loaded from separate files.
    """

    camera: CameraSettings = field(default_factory=CameraSettings)
    frame_line: FrameLineRect = field(default_factory=FrameLineRect)


# ---------------------------------------------------------------------------
# XML serialisation
# ---------------------------------------------------------------------------


def _fmt_float(value: float) -> str:
    """Format a float, stripping unnecessary trailing zeros but keeping precision."""
    if value == int(value):
        return str(int(value))
    return f"{value:.15g}"


def to_xml_element(frameline: SonyFrameline) -> ET.Element:
    """Build an ElementTree Element from a SonyFrameline."""
    root = ET.Element("FrameLineSetting")

    version_el = ET.SubElement(root, "FileFormatVersion")
    version_el.set("version", "1")

    cam_group = ET.SubElement(root, "Group")
    cam_item = ET.SubElement(cam_group, "Item")
    cam_item.set("id", f"{_ID_PREFIX}{_CAMERA_SETTINGS_SUFFIX}")
    cam_item.set("label", "FileTransfer.CheckingCameraSettings")
    model_el = ET.SubElement(cam_item, "CameraModel")
    model_el.text = frameline.camera.model_code
    mode_el = ET.SubElement(cam_item, "ImagerMode")
    mode_el.text = frameline.camera.imager_mode

    rect = frameline.frame_line
    group = ET.SubElement(root, "Group")
    corners = {
        "TopLeft": rect.top_left,
        "TopRight": rect.top_right,
        "BottomLeft": rect.bottom_left,
        "BottomRight": rect.bottom_right,
    }
    for corner_name, point in corners.items():
        suffix = _CORNER_SUFFIXES[corner_name]
        item = ET.SubElement(group, "Item")
        item.set("id", f"{_ID_PREFIX}{suffix}")
        item.set("label", f"FileTransfer.FrameLineSettings.{corner_name}")
        top_el = ET.SubElement(item, "Top")
        top_el.text = _fmt_float(point.top)
        left_el = ET.SubElement(item, "Left")
        left_el.text = _fmt_float(point.left)

    type_item = ET.SubElement(root, "Item")
    type_item.set("id", f"{_ID_PREFIX}{_TYPE_SUFFIX}")
    type_item.set("label", "FileTransfer.FrameLineSettings.Type")
    color_el = ET.SubElement(type_item, "color")
    color_el.text = rect.color

    return root


def write_xml(frameline: SonyFrameline, path: str | Path) -> None:
    """Serialise a SonyFrameline to an XML file."""
    root = to_xml_element(frameline)
    ET.indent(root, space="    ")
    tree = ET.ElementTree(root)
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    tree.write(str(path), encoding="UTF-8", xml_declaration=True)
    with open(path, "a") as fh:
        fh.write("\n")


def to_xml_string(frameline: SonyFrameline) -> str:
    """Serialise a SonyFrameline to an XML string."""
    root = to_xml_element(frameline)
    ET.indent(root, space="    ")
    return '<?xml version="1.0" encoding="UTF-8"?>\n' + ET.tostring(root, encoding="unicode")


# ---------------------------------------------------------------------------
# XML parsing
# ---------------------------------------------------------------------------


def _text(parent: ET.Element, tag: str, default: str = "") -> str:
    el = parent.find(tag)
    if el is not None and el.text:
        return el.text.strip()
    return default


def _parse_frameline_rect(items: dict[str, ET.Element]) -> FrameLineRect:
    """Parse the frame line rectangle from the XML items dict."""
    corners: dict[str, CornerPoint] = {}
    for corner_name, suffix in _CORNER_SUFFIXES.items():
        item_id = f"{_ID_PREFIX}{suffix}"
        item = items.get(item_id)
        if item is None:
            raise ValueError(f"Missing required item {item_id} ({corner_name})")
        corners[corner_name] = CornerPoint(
            top=float(_text(item, "Top", "0")),
            left=float(_text(item, "Left", "0")),
        )

    type_id = f"{_ID_PREFIX}{_TYPE_SUFFIX}"
    type_item = items.get(type_id)
    color = "White"
    if type_item is not None:
        color = _text(type_item, "color", "White")

    return FrameLineRect(
        top_left=corners["TopLeft"],
        top_right=corners["TopRight"],
        bottom_left=corners["BottomLeft"],
        bottom_right=corners["BottomRight"],
        color=color,
    )


def from_xml_element(root: ET.Element) -> SonyFrameline:
    """Build a SonyFrameline from a parsed XML Element."""
    camera = CameraSettings()

    items: dict[str, ET.Element] = {}
    for item in root.iter("Item"):
        item_id = item.get("id", "")
        if item_id:
            items[item_id] = item

    cam_id = f"{_ID_PREFIX}{_CAMERA_SETTINGS_SUFFIX}"
    cam_item = items.get(cam_id)
    if cam_item is not None:
        camera.model_code = _text(cam_item, "CameraModel")
        camera.imager_mode = _text(cam_item, "ImagerMode")

    frame_line = _parse_frameline_rect(items)

    return SonyFrameline(camera=camera, frame_line=frame_line)


def read_xml(path: str | Path) -> SonyFrameline:
    """Parse a Sony frameline XML file into a SonyFrameline model."""
    tree = ET.parse(str(path))
    return from_xml_element(tree.getroot())


def from_xml_string(xml_str: str) -> SonyFrameline:
    """Parse a Sony frameline XML string into a SonyFrameline model."""
    root = ET.fromstring(xml_str)
    return from_xml_element(root)
